function() {
  var el = document.getElementById('__pl_user_data__');
  if (!el) return undefined;
  var d = el.dataset;
  var hasAny = d.email || d.phone || d.firstName || d.lastName ||
               d.city || d.postalCode || d.country;
  if (!hasAny) return undefined;
  var data = {};
  if (d.email)     data.email        = d.email;
  if (d.phone)     data.phone_number = d.phone;
  var addr = {};
  if (d.firstName)  addr.first_name  = d.firstName;
  if (d.lastName)   addr.last_name   = d.lastName;
  if (d.city)       addr.city        = d.city;
  if (d.postalCode) addr.postal_code = d.postalCode;
  if (d.country)    addr.country     = d.country;
  if (Object.keys(addr).length) data.address = addr;
  return data;
}
